import{_ as a,o as e,c as l,a7 as i}from"./chunks/framework.C5fSpjcB.js";const f=JSON.parse('{"title":"カードシステム概要","description":"","frontmatter":{},"headers":[],"relativePath":"ja/cards/index.md","filePath":"ja/cards/index.md","lastUpdated":1775394001000}'),r={name:"ja/cards/index.md"};function d(n,t,s,o,h,c){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="カードシステム概要" tabindex="-1">カードシステム概要 <a class="header-anchor" href="#カードシステム概要" aria-label="Permalink to &quot;カードシステム概要&quot;">​</a></h1><p>忘却前夜はローグライト×デッキ構築型のバトルシステムを採用しています。覚醒体が使用する<strong>カード</strong>を理解することが攻略の鍵です。</p><h2 id="カードの種類" tabindex="-1">カードの種類 <a class="header-anchor" href="#カードの種類" aria-label="Permalink to &quot;カードの種類&quot;">​</a></h2><h3 id="指令カード-command-card" tabindex="-1">指令カード（Command Card） <a class="header-anchor" href="#指令カード-command-card" aria-label="Permalink to &quot;指令カード（Command Card）&quot;">​</a></h3><p>覚醒体の基本的な攻撃・スキルに相当するカードです。</p><ul><li>各覚醒体は固有の指令カードセットを持つ</li><li>戦闘中にデッキからドローして手札に加え、算力を消費して使用</li><li>強化により最大<strong>Lv.6</strong>まで性能向上可能</li></ul><h3 id="魂覚醒カード-spirit-awakening-card" tabindex="-1">魂覚醒カード（Spirit Awakening Card） <a class="header-anchor" href="#魂覚醒カード-spirit-awakening-card" aria-label="Permalink to &quot;魂覚醒カード（Spirit Awakening Card）&quot;">​</a></h3><p>覚醒体の必殺技に相当する特別なカードです。</p><ul><li><strong>狂気ゲージが100</strong>に到達すると使用可能</li><li>非常に強力な効果を持つが、使用後は狂気ゲージがリセットされる</li><li>啓霊4凸で強化版が解放される</li></ul><h2 id="算力-arithmetica" tabindex="-1">算力（Arithmetica） <a class="header-anchor" href="#算力-arithmetica" aria-label="Permalink to &quot;算力（Arithmetica）&quot;">​</a></h2><p>カードの使用にはコストとして**算力（Arithmetica）**を消費します。</p><ul><li>毎ターン<strong>5算力</strong>が回復する</li><li>超維界域のシナジーや一部カード効果で追加回復が可能</li><li>高コストカードほど強力だが、算力管理が重要</li></ul><h2 id="狂気-madness-ゲージ" tabindex="-1">狂気（Madness）ゲージ <a class="header-anchor" href="#狂気-madness-ゲージ" aria-label="Permalink to &quot;狂気（Madness）ゲージ&quot;">​</a></h2><ul><li>戦闘中にカード使用・被ダメージ等で<strong>狂気ゲージ</strong>が蓄積</li><li><strong>100に到達</strong>すると魂覚醒カードが使用可能（バースト）</li><li>混沌界域の覚醒体は狂気蓄積が速い</li></ul><h2 id="カード属性" tabindex="-1">カード属性 <a class="header-anchor" href="#カード属性" aria-label="Permalink to &quot;カード属性&quot;">​</a></h2><p>各カードには以下の属性情報があります。</p><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">説明</th></tr></thead><tbody><tr><td style="text-align:left;">コスト</td><td style="text-align:left;">使用に必要な算力（0〜5）</td></tr><tr><td style="text-align:left;">界域</td><td style="text-align:left;">所属する界域（混沌/深海/血肉/超維）</td></tr><tr><td style="text-align:left;">タイプ</td><td style="text-align:left;">攻撃/防御/支援/特殊</td></tr><tr><td style="text-align:left;">レアリティ</td><td style="text-align:left;">N/R/SR/SSR</td></tr><tr><td style="text-align:left;">強化レベル</td><td style="text-align:left;">Lv.1〜Lv.6</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./list.html">カード一覧</a></li><li><a href="./upgrade.html">カード強化</a></li><li><a href="./deckbuilding.html">デッキ構築ガイド</a></li><li><a href="./../modes/combat.html">戦闘システム</a></li><li><a href="./../awakeners/">覚醒体図鑑</a></li></ul>',19)])])}const u=a(r,[["render",d]]);export{f as __pageData,u as default};
